INSERT INTO `tbl_connection` (`id`, `location_a_id`, `location_b_id`, `weight`, `pmr`, `instruction_a_to_b`, `instruction_b_to_a`, `image_a_to_b`, `image_b_to_a`) VALUES
	(1, 9, 23, 1, 1, 'Passer par la porte qui est à droite quand on regarde vers les portes coulissantes, sur la porte il y a un cadre "secretariat".', 'Passer par la porte.', NULL, NULL),
	(2, 9, 2, 1, 1, 'Passer par les portes coulissantes et se sera la partie gauche du couloir.', 'Quand on arrive devant une heure numérique rouge, on peut voir des portes coulissantes, il faut passer par les portes coulissantes.', NULL, NULL),
	(3, 2, 6, 1, 0, 'Si vous voyez une heure numérique rouge, vous devez voir des escaliers derrière.', 'Si vous voyez une heure numérique rouge, le couloir est derrière et se sera la partie à votre droite.', '2_6.jpg', '6_2.jpg'),
	(4, 6, 10, 1, 0, 'En montant une partie des escaliers, il y a une grande porte avec le cadre "salle du mont".', 'Passer par la grande porte.', NULL, NULL),
	(5, 2, 12, 1, 1, 'La salle S7 a une porte avec un cadre "7", si vous êtes au niveau des portes coulissantes se sera la 2ème porte à votre gauche, si vous êtes dans un carrefour se sera la 5ème porte à votre droite.', 'Passer par la porte.', NULL, NULL),
	(6, 2, 13, 1, 1, 'La salle S11 a une porte avec un cadre "11", si vous êtes au niveau des portes coulissantes se sera la 3ème porte à votre gauche, si vous êtes dans un carrefour se sera la 4ème porte à votre droite.', 'Passer par la porte.', NULL, NULL),
	(7, 2, 14, 1, 1, 'La salle S15 a une porte avec un cadre "15", si vous êtes au niveau des portes coulissantes se sera la 3ème porte à votre gauche, si vous êtes dans un carrefour se sera la 3ème porte à votre droite.', 'Passer par la porte.', NULL, NULL),
	(8, 2, 15, 1, 1, 'La salle S19 a une porte avec un cadre "19", si vous êtes au niveau des portes coulissantes se sera la 4ème porte à votre gauche, si vous êtes dans un carrefour se sera la 2ème porte à votre droite.', 'Passer par la porte.', NULL, NULL),
	(9, 2, 16, 1, 1, 'Le foyer TV a une porte avec un cadre "foyer TV", si vous êtes au niveau des portes coulissantes se sera la 5ème porte à votre gauche, si vous êtes dans un carrefour se sera la 1ère porte à votre droite.', 'Passer par la porte.', NULL, NULL),
	(10, 2, 157, 1, 1, 'Aller devant les portes coulissantes au milieu du couloir, en regardant les portes coulissantes aller à votre droite jusqu\'à être à un endroit avec plusieurs chemins.', 'Regarder autour de vous, le couloir principal est le couloir qui est le plus long.', NULL, NULL),
	(11, 157, 17, 1, 1, 'Regarder vers le couloir principal, retournez-vous et se sera la portre de gauche.', 'Passer par la porte.', NULL, NULL),
	(12, 157, 22, 1, 1, 'Regarder autour de vous jusqu\'à voir des portes rouges, passer par les portes rouge, vous devrez voir des casiers dans la pièce où vous êtes, les 2 portes mènent à la cantine.', 'Regarder vers les fenêtres ,tournez-vous vers la droite, il devrai y avoir une porte, passer la, normalement vous êtes dans une pièce avec des casiers, passer dans le passage qui est entre les casiers.', NULL, NULL),
	(13, 157, 1, 1, 1, 'Regarder autour de vous jusqu\'à voir un ascenseur gris.', 'Quand vous sortez de l\'ascenseur, aller dans le passage qui est en face.', '157_1.jpg', '1_157.jpg'),
	(14, 157, 8, 1, 0, 'Regarder autour de vous jusqu\'à voir l\'ascenseur, aller vers l\'ascenseur, tourner a gauche et normalement vous devriez voir des escaliers.', 'Regarder la porte qui mène à la cour, tourner a droite, il devrai y avoir un passage.', NULL, NULL),
	(15, 2, 20, 1, 1, 'La salle immanuel kant est une porte à carreaux vitrés qui a des fenètres à côté, si vous êtes au niveau des portes coulissantes la porte sera à votre droite, si vous êtes dans un carrefour la porte sera à votre gauche.', 'Passer par la porte à carreaux vitrés.', NULL, NULL),
	(16, 20, 21, 1, 1, 'C\'est la porte à gauche des fauteuils bleus et gris.', 'Regarder la porte qui mène à la cour, retournez-vous, il devrai y avoir une porte.', NULL, NULL),
	(17, 2, 19, 1, 1, 'Si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre droite. Si vous êtes au niveau du carrefour se sera à votre gauche, il y aura 3 portes et la salle "info autonomie" sera la porte qui est à gauche quand on regarde du couloir.', 'Passer par la porte.', NULL, NULL),
	(18, 2, 18, 1, 1, 'Le cadre educatif a une porte avec un tape code à côté. Si vous êtes au niveau des portes coulissantes se sera la 1ère porte à votre droite. Si vous êtes au niveau du carrefour se sera la 3ème porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(19, 3, 24, 1, 1, 'L\'adjoint de direction a une porte avec un cadre "adjoint de direction". Si vous êtes au niveau des portes coulissantes se sera la 1ère porte à votre droite. Si vous êtes au niveau du croisement des couloirs se sera la 6ème porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(20, 3, 25, 1, 1, 'La direction a une porte avec un cadre "direction". Si vous êtes au niveau des portes coulissantes se sera la 2ème porte à votre droite. Si vous êtes au niveau du croisement des couloirs se sera la 5ème porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(21, 3, 26, 1, 1, 'La salle S10 a une porte avec un cadre "10". Si vous êtes au niveau des portes coulissantes se sera la 3ème porte à votre droite. Si vous êtes au niveau du croisement des couloirs se sera la 4ème porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(22, 3, 27, 1, 1, 'La salle S14 a une porte avec un cadre "14". Si vous êtes au niveau des portes coulissantes se sera la 4ème porte à votre droite. Si vous êtes au niveau du croisement des couloirs se sera la 3ème porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(23, 3, 28, 1, 1, 'La salle S18 a une porte avec un cadre "18". Si vous êtes au niveau des portes coulissantes se sera la 5ème porte à votre droite. Si vous êtes au niveau du croisement des couloirs se sera la 2ème porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(24, 3, 29, 1, 1, 'La salle FC-PRO a une porte  près d\'un extincteur de feu avec un cadre "FC-PRO". Si vous êtes au niveau des portes coulissantes se sera la 6ème porte à votre droite. Si vous êtes au niveau du croisement des couloirs se sera la 1ère porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(25, 3, 35, 1, 1, 'Si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre gauche. Si vous êtes au niveau du croisement de couloir se sera à votre droite. Il y aura 3 portes et la salle S8 sera la porte qui est à gauche quand on regarde du couloir.', 'Passer par la porte.', NULL, NULL),
	(26, 3, 36, 1, 1, 'Si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre gauche. Si vous êtes au niveau du croisement de couloir se sera à votre droite. Il y aura 3 portes et la salle RDV sera la porte qui est au milieu quand on regarde du couloir.', 'Passer par la porte.', NULL, NULL),
	(27, 3, 37, 1, 1, 'Si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre gauche. Si vous êtes au niveau du croisement de couloir se sera à votre droite. Il y aura 3 portes et le foyer baby sera la porte qui est à droite quand on regarde du couloir.', 'Passer par la porte.', NULL, NULL),
	(28, 3, 38, 1, 1, 'La porte pour aller aux casiers est un porte vitrés qui est à votre droite si vous êtes au niveau du croisement des couloirs ou à votre gauche si vous êtes au niveau des portes coulissantes.', 'En regardant les casiers, regarder à gauche, il devrai y avoir une porte.', NULL, NULL),
	(29, 38, 39, 1, 1, 'En regardant les casiers, retournez-vous, normalement vous devriez voir une porte vitrée marron.', 'Regarder du côté des fenêtres, regarder à votre gauche, normalement vous verrez une porte vitrée marron.', NULL, NULL),
	(30, 2, 3, 1, 1, 'Avancer dans le couloir jusqu\'à passer devant des portes coulissantes, quand vous passerez devant vous serez dans le couloir principal droite.', 'Avancer jusqu\'à passer devant des portes coulissantes, quand vous passerez devant vous serez dans le couloir principal gauche.', NULL, NULL),
	(31, 3, 122, 1, 1, 'Avancer jusqu\'à être dans un croisement de couloir, se sera le couloir en face.', 'Avancer jusqu\'à être dans un croisement de couloir, se sera le couloir en face.', NULL, NULL),
	(32, 3, 4, 1, 1, 'Avancer jusqu\'à être dans un croisement de couloir, se sera le couloir à votre gauche.', 'Avancer jusqu\'à être dans un croisement de couloir, se sera le couloir à votre droite.', NULL, NULL),
	(33, 122, 30, 1, 1, 'Mettez-vous au niveau du croisement de couloirs, se sera la 1ère porte à droite.', 'Passer par la porte.', NULL, NULL),
	(34, 122, 31, 1, 1, 'Mettez-vous au niveau du croisement de couloirs, avancer dans le couloir jusqu\'à la 2ème porte à droite avec le cadre "24 bis".', 'Passer par la porte.', NULL, NULL),
	(35, 122, 32, 1, 1, 'Mettez-vous au niveau du croisement de couloirs, avancer dans le couloir jusqu\'à la 3ème porte à droite qui a un cadre "26".', 'Passer par la porte.', NULL, NULL),
	(36, 122, 33, 1, 1, 'Mettez-vous au niveau du croisement de couloirs, avancer dans le couloir jusqu\'à la 4ème porte à droite avec un cadre "26 bis".', 'Passer par la porte.', NULL, NULL),
	(37, 122, 34, 1, 1, 'Tournez-vous comme si vous venez du croisement de couloirs, se sera la dernière porte à droite.', 'Passer par la porte.', NULL, NULL),
	(38, 122, 40, 1, 1, 'Mettez-vous au niveau du croisement de couloirs, avancer jusqu\'à voir la porte avec un cadre "espace détente".', 'Passer par la porte.', NULL, NULL),
	(39, 122, 41, 1, 1, 'Mettez-vous au niveau du croisement de couloirs, avancer jusqu\'à voir une porte avec un cadre "pôle pro".', 'Passer par la porte.', NULL, NULL),
	(40, 122, 42, 1, 1, 'Aller au fond du couloir, se sera la dernière porte à gauche.', 'Passer par la porte.', NULL, NULL),
	(41, 4, 7, 1, 0, 'Aller au niveau du couloir et avancer un peu et les escaliers seront à droite.', 'Descendre les escaliers.', NULL, NULL),
	(42, 4, 43, 1, 1, 'Aller devant les escaliers, avancer jusqu\'au toilette, avancer jusqu\'à la prochaine porte.', 'Passer par la porte.', NULL, NULL),
	(43, 4, 44, 1, 1, 'Aller devant les escaliers, avancer jusqu\'à la 2ème porte qui a le cadre "petit amphi".', 'Regarder le tableau, tourner sur votre gauche, passer par la porte.', NULL, NULL),
	(44, 4, 45, 1, 1, 'Aller devant les escaliers, avancer jusqu\'à la 3ème porte avec le cadre "34".', 'Passer la porte qui est à droite quand on regarde le tableau.', NULL, NULL),
	(45, 4, 46, 1, 1, 'La porte de la salle se trouve au fond du couloir, il y a juste à avancer.', 'Passer par la porte.', NULL, NULL),
	(46, 2, 11, 1, 1, 'La porte de la vie solaire est celle avec un cadre "bureau vie scolaire" si vous êtes au niveau des portes coulissantes se sera la 1ère porte à gauche, si vous êtes au niveau du carrefour se sera la 6ème porte à droite.', 'Passer par la porte.', NULL, NULL),
	(47, 44, 45, 1, 1, 'La porte qui mène à la salle S34 est à droite du tableau.', 'La porte qui mène à la salle S32 est à gauche du tableau.', NULL, NULL),
	(48, 8, 54, 1, 0, 'Monter les escaliers jusqu\'au 1er étage.', 'Descendre les escaliers jusqu\'au rez de chausée.', NULL, NULL),
	(49, 7, 53, 1, 0, 'Monter les escaliers jusqu\'au 1er étage.', 'Descendre les escaliers.', NULL, NULL),
	(50, 6, 52, 1, 0, 'Monter les escaliers jusqu\'au 1er étage.', 'Descendre les escaliers.', NULL, NULL),
	(51, 1, 47, 1, 1, 'Aller au 1er étage.', 'Aller au rez de chausée.', NULL, NULL),
	(52, 53, 50, 1, 0, 'Normalement vous êtes dans un couloir et près de l\'escalier qui monte un cadre avec des infos sur le 1er étage.', 'Mettez-vous au niveau du carrefour, avancer un peu et il y aura les escaliers à droite.', '53_50.jpg', '50_53.jpg'),
	(53, 54, 158, 1, 0, 'Normalement vous êtes à un endroit avec 2 passages.', 'Si vous aller au bout du couloir principal du 1er étage devant l\'infirmerie, mettez vous fasse a la porte et aller à droite, il y aura les escaliers sur votre gauche.', NULL, NULL),
	(54, 52, 48, 1, 0, 'Normalement vous êtes dans un couloir avec une grande porte en face et quand vous regardez sur les côtés il y a des grandes portes aussi.', 'Aller devant la grande porte au milieu du couloir, si vous regardez la grande porte les escaliers sont derrière vous.', '52_48.jpg', '48_52.jpg'),
	(55, 158, 66, 1, 1, 'Si vous regarder les escaliers, à droite il y a un couloir, aller dans le couloir et le labo SVT sera à gauche.', 'Passer par la porte.', NULL, NULL),
	(56, 158, 67, 1, 1, 'Si vous regarder les escaliers, aller à droite et aller au fond du couloir.', 'Passer par la porte.', NULL, NULL),
	(57, 158, 48, 1, 1, 'Si vous regarder les escaliers, aller à gauche.', 'Mettez vous face a la porte de l\'infirmerie, c\'est à droite.', NULL, NULL),
	(58, 47, 158, 1, 1, 'Sortez de l\'ascenceur.', 'Si vous regardez les escaliers, tourner à droite, il devrai y avoir un couloir et à côté du couloir l\'ascenseur.', NULL, NULL),
	(59, 48, 65, 1, 1, 'Aller à l\'escalier principal, en regardant l\'escalier aller à votre gauche, passer les grandes portes, et la porte de l\'infirmerie sera au fond. Si vous êtes au niveau du bout du couloir se sera juste à droite quand vous aller dans le couloir principal.', 'Passer par la porte.', NULL, NULL),
	(60, 48, 55, 1, 1, 'Aller à l\'escalier principal au mileu du couloir, regarder l\'escalier et la salle 100 sera derrière vous. Si vous êtes au niveau du bout du couloir avancer, passer les grandes portes et avancer jusqu\'à l\'escalier principal.', 'Passer par la porte.', NULL, NULL),
	(61, 48, 56, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regarder l\'escalier et aller à votre gauche, se sera la 1ère porte avec un cadre "comptabilité". Si vous êtes au niveau du bout du couloir, passer par les grandes portes et se sera la 4ème porte.', 'Passer par la porte.', NULL, NULL),
	(62, 48, 57, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre gauche, se sera la 2ème porte avec un cadre avec le numéro "103". Si vous êtes au niveau du bout du couloir, passer par les grandes portes et c\'est la 3ème porte.', 'Passer par la porte.', NULL, NULL),
	(63, 48, 58, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre gauche jusqu\'à la 3ème porte avec un cadre qui a le numéro "105". Si vous êtes au niveau du bout du couloir, passer par les grandes portes et c\'est la 2ème porte.', 'Passer par la porte.', NULL, NULL),
	(64, 48, 70, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre gauche jusqu\'à la 4ème porte avec un cadre "coordinateur pédagogique". Si vous êtes au niveau du bout du couloir, passer les grandes portes et c\'est la 1ère porte.', 'Passer par la porte.', NULL, NULL),
	(65, 48, 60, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre gauche, passer par les grandes portes et aller jusqu\'à la 1ère porte avec un cadre qui a le numéro "111". Si vous êtes au niveau du bout du couloir c\'est la 5ème porte.', 'Passer par la porte.', NULL, NULL),
	(66, 48, 61, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à gauche, passer les grandes portes et aller jusqu\'à la 2ème porte avec un cadre qui a le numéro "115". Si vous êtes au niveau du bout du couloir c\'est la 4ème porte.', 'Passer par la porte.', NULL, NULL),
	(67, 48, 62, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller sur votre gauche, passer les grandes portes et aller jusqu\'à la 3ème porte avec le cadre "119". Si vous êtes au niveau du bout du couloir c\'est la 3ème porte.', 'Passer par la porte.', NULL, NULL),
	(68, 48, 63, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre gauche, passer les grandes portes et aller jusqu\'à la 4ème porte avec le cadre "121". Si vous êtes au niveau du bout du couloir, passer par les grandes portes et c\'est la 2ème porte.', 'Passer par la porte.', NULL, NULL),
	(69, 48, 64, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre gauche, passer par les grandes portes et aller jusqu\'à la 5ème porte avec un cadre qui a le numéro "123". Si vous êtes au niveau du bout du couloir c\'est la 1ère porte.', 'Passer par la porte.', NULL, NULL),
	(70, 49, 68, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite jusqu\'à voir la porte avec le cadre "salle des profs", sa devrai être la 1ère porte. Si vous êtes au niveau du croisement de couloirs, passer les grandes portes et c\'est la 3ème porte.', 'Passer par la porte.', NULL, NULL),
	(71, 49, 69, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite jusqu\'à la 2ème porte avec le cadre "responsable informatique". Si vous êtes au niveau du croisement de couloirs, passer les grandes portes et c\'est la 2ème porte.', 'Passer par la porte.', NULL, NULL),
	(72, 49, 70, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite jusqu\'à la 3ème porte avec le cadre "coordinateur pédagogique". Si vous êtes au niveau du croisement de couloir, passer par les grandes portes et c\'est la 1ère porte.', 'Passer par la porte.', NULL, NULL),
	(73, 49, 71, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite, passer les grandes portes et aller jusqu\'à la 1ère porte qui a le cadre avec le numéro "112". Si vous êtes au niveau du croisement de couloirs c\'est la 4ème porte.', 'Passer par la porte.', NULL, NULL),
	(74, 49, 72, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite, passer les grandes portes et aller jusqu\'à la 2ème porte qui a le cadre avec le numéro "114". Si vous êtes au niveau du croisement de couloirs c\'est la 3ème porte.', 'Passer par la porte.', NULL, NULL),
	(75, 49, 73, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite, passer les grandes portes et aller jusqu\'à la 3ème porte avec le cadre qui a le numéro "118". Si vous êtes au niveau du croisement de couloirs c\'est la 2ème porte sans compter la salle S124.', 'Passer par la porte.', NULL, NULL),
	(76, 72, 73, 1, 1, 'Regarder le tableau et retournez-vous derrière, la porte sera au fond de la salle et mène à la salle S118.', 'La porte est à droite du tableau et mène à la salle S114.', NULL, NULL),
	(77, 49, 74, 1, 1, 'Aller à l\'escalier principal au milieu du couloir, en regardant l\'escalier aller à votre droite, passer par les grandes portes et aller jusqu\'à voir une porte avec le cadre qui a le numéro "122", la porte est entre 2 extincteurs de feu. Si vous êtes au niveau du croisement de couloirs c\'est la 1ère porte.', 'Passer par la porte.', NULL, NULL),
	(78, 49, 50, 1, 1, 'Aller au croisement de couloirs, se sera le couloir qui est à votre gauche.', 'Regarder la salle S124, le couloir principal droite est à votre droite.', NULL, NULL),
	(79, 50, 75, 1, 1, 'Regarder autour de vous et vous verrez la porte avec le cadre "124".', 'Passer par la porte.', NULL, NULL),
	(80, 49, 162, 1, 1, 'Aller au croisement de couloirs, c\'est le couloir d\'en face.', 'Aller au croisement de couloirs et se sera le couloir à gauche. Si vous êtes au niveau des escaliers principal il faudra passer par les grandes portes.', NULL, NULL),
	(81, 162, 160, 1, 1, 'Aller au niveau du croisement de couloirs, avancer un peu et se sera la 1ère salle à votre droite.', 'Passer par la porte.', NULL, NULL),
	(82, 162, 76, 1, 1, 'Aller au niveau du croisement de couloirs et avancer jusqu\'à la 2ème porte à droite avec le cadre "126 bis".', 'Passer par la porte.', NULL, NULL),
	(83, 160, 76, 1, 1, 'Regarder le tableau et retournez-vous, la porte est au fond de la salle et mène à la salle S126 bis.', 'La porte qui mène à la salle S126 est à gauche du tableau.', '160_76.jpg', '76_160.jpg'),
	(84, 162, 77, 1, 1, 'Aller au niveau du croisement de couloirs et avancer jusqu\'à la 3ème porte à droite avec le cadre "126 ter".', 'Passer par la porte.', NULL, NULL),
	(85, 50, 78, 1, 1, 'Aller au niveau du croisement de couloirs, avancer un peu et se sera la 1ère porte à votre gauche.', 'Passer par la porte.', NULL, NULL),
	(86, 162, 50, 1, 1, 'Aller au croisement de couloirs et se sera le couloir à votre droite.', 'Aller au croisement de couloirs et se sera le couloir à votre gauche.', NULL, NULL),
	(87, 50, 80, 1, 1, 'Regarder les escaliers et aller à votre gauche, se sera la porte qui est à côté des toilettes.', 'Passer par la porte.', NULL, NULL),
	(88, 50, 81, 1, 1, 'Regarder les escaliers et aller à votre gauche jusqu\'à voir un mur un peu reculé à droite, il y aura la porte avec le cadre "132".', 'Passer par la porte.', NULL, NULL),
	(89, 50, 82, 1, 1, 'Regarder les escaliers et aller à votre gauche jusqu\'à la porte qui est au fond et entrer dans la salle.', 'Passer par la porte.', '50_82.jpg', '82_50.jpg'),
	(90, 82, 83, 1, 1, 'La porte qui mène à la salle S138 est à côté de l\'ordi du prof.', 'La porte qui mène à la salle S136 est à droite du tableau.', '82_83.jpg', '83_82.jpg'),
	(91, 53, 79, 1, 1, 'Monter les escaliers sans aller à l\'étage superieur, il y aura une porte entre les 2 parties de l\'escalier.', 'Passer par la porte.', NULL, NULL),
	(92, 162, 123, 1, 1, 'Aller au fond du couloir, il y aura une porte avec des escaliers derrière, monter les escaliers et vous serez à la salle "S242".', 'Passer par la porte.', NULL, NULL),
	(93, 47, 92, 1, 1, 'Monter dans l\'ascenseur et choisissez l\'étage 2.', 'Monter dans l\'asccenseur et choisissez l\'étage 1.', NULL, NULL),
	(94, 52, 96, 1, 0, 'Monter les escaliers de l\'étage 1 pour aller à l\'étage 2.', 'Descendre les escaliers de l\'étage 2 pour aller à l\'étage 1.', NULL, NULL),
	(95, 53, 97, 1, 0, 'Monter les escaliers de l\'étage 1 pour aller à l\'étage 2.', 'Descendre les escaliers de l\'étage 2 pour aller à l\'étage 1.', NULL, NULL),
	(96, 54, 98, 1, 0, 'Monter les escaliers de l\'étage 1 pour aller à l\'étage 2.', 'Descendre les escaliers de l\'étage 2 pour aller à l\'étage 1.', NULL, NULL),
	(97, 9, 3, 1, 1, 'Passer par les portes coulissantes, se sera vers votre droite.', 'Quand vous serez devant une heure numérique rouge, se sera les portes coulissantes qui seront à votre gauche.', NULL, NULL),
